{{category_name}} --- <<<<<<<<<<<< {{path}}.events.{{category_name|lower|replace(' ', '_')}}
{% for name, event_data in category_data.items() %}{{category_name[:-1]}} -- {{name}} <<<<<<<<<<<< {{path}}.events.{{category_name|lower|replace(' ', '_')}}.{{name}}
